// ── Supabase REST helper ──
async function supaFetch(path, { method = "GET", body, token, headers = {} } = {}) {
  const res = await fetch(`${SUPA_URL}${path}`, {
    method,
    headers: { apikey: SUPA_KEY, Authorization: `Bearer ${token || SUPA_KEY}`, "Content-Type": "application/json", ...headers },
    body: body ? JSON.stringify(body) : undefined,
  });
  if (!res.ok) { const t = await res.text().catch(() => ""); throw new Error(`Supabase ${res.status}${t ? `: ${t.slice(0, 140)}` : ""}`); }
  const text = await res.text();
  return text ? JSON.parse(text) : null;
}

// ── Library file upload → public Supabase Storage bucket "library". ──
// Returns a permanent public URL. (Unrestricted for now; per-plan limits come later.)
async function uploadToLibrary(file) {
  const ext = (file.name.match(/\.[a-z0-9]+$/i) || [""])[0].toLowerCase();
  const path = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}${ext}`;
  const res = await fetch(`${SUPA_URL}/storage/v1/object/library/${path}`, {
    method: "POST",
    headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}`, "Content-Type": file.type || "application/octet-stream", "x-upsert": "true" },
    body: file,
  });
  if (!res.ok) { const t = await res.text().catch(() => ""); throw new Error(`Upload ${res.status}${t ? `: ${t.slice(0, 140)}` : ""}`); }
  return `${SUPA_URL}/storage/v1/object/public/library/${path}`;
}

// ── Per-user media library ("Filebase") in the public "media" bucket. ──
// Objects live under "<userId>/…" and per-user RLS lets only the owner write/list/delete.
// Public read so the files work inside published schools and blocks.
const MEDIA_MAX_BYTES = 50 * 1024 * 1024; // 50 MB/file (per-plan quotas come later)
const mediaPublicUrl = (path) => `${SUPA_URL}/storage/v1/object/public/media/${path.split("/").map(encodeURIComponent).join("/")}`;
const isImageFile = (m) => /^image\//.test(m.type || "") || /\.(png|jpe?g|gif|webp|svg|avif|bmp)$/i.test(m.name || m.path || "");
async function uploadMedia(file, token, userId, opts = {}) {
  if (file.size > MEDIA_MAX_BYTES) throw new Error("File too large (max 50 MB).");
  const ext = (file.name.match(/\.[a-z0-9]+$/i) || [""])[0].toLowerCase();
  const stem = file.name.replace(/\.[a-z0-9]+$/i, "").replace(/[^a-z0-9._-]+/gi, "-").slice(0, 48) || "file";
  // opts.path → overwrite that exact object (WP-style "save & replace", keeps the same URL).
  const path = opts.path || `${userId}/${Date.now()}-${Math.random().toString(36).slice(2, 7)}-${stem}${ext}`;
  const res = await fetch(`${SUPA_URL}/storage/v1/object/media/${path.split("/").map(encodeURIComponent).join("/")}`, {
    method: "POST",
    headers: { apikey: SUPA_KEY, Authorization: `Bearer ${token}`, "Content-Type": file.type || "application/octet-stream", "x-upsert": "true" },
    body: file,
  });
  if (!res.ok) { const t = await res.text().catch(() => ""); throw new Error(`Upload ${res.status}${t ? `: ${t.slice(0, 140)}` : ""}`); }
  return { path, url: mediaPublicUrl(path), name: file.name, type: file.type, size: file.size, created: new Date().toISOString() };
}
async function listMedia(token, userId) {
  const res = await fetch(`${SUPA_URL}/storage/v1/object/list/media`, {
    method: "POST",
    headers: { apikey: SUPA_KEY, Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
    body: JSON.stringify({ prefix: `${userId}/`, limit: 200, sortBy: { column: "created_at", order: "desc" } }),
  });
  if (!res.ok) throw new Error(`List ${res.status}`);
  const rows = await res.json();
  return (Array.isArray(rows) ? rows : []).filter(o => o.name && o.id != null).map(o => {
    const path = `${userId}/${o.name}`;
    return { path, url: mediaPublicUrl(path), name: o.name.replace(/^\d+-[a-z0-9]+-/i, ""), type: o.metadata?.mimetype || "", size: o.metadata?.size || 0, created: o.created_at };
  });
}
async function deleteMedia(path, token) {
  const res = await fetch(`${SUPA_URL}/storage/v1/object/media/${path.split("/").map(encodeURIComponent).join("/")}`, {
    method: "DELETE", headers: { apikey: SUPA_KEY, Authorization: `Bearer ${token}` },
  });
  if (!res.ok) { const t = await res.text().catch(() => ""); throw new Error(`Delete ${res.status}${t ? `: ${t.slice(0, 140)}` : ""}`); }
}
// ── AI image generation → straight into the creator's media library. ──
// The OpenAI key lives ONLY in the "image-gen" edge function (server-side).
// The API only outputs 1:1 / 3:2 / 2:3 — we generate at the closest size and
// centre-crop client-side to the EXACT ratio requested.
const IMG_RATIOS = { "1:1": [1, 1], "16:9": [16, 9], "9:16": [9, 16], "4:5": [4, 5], "5:4": [5, 4] };
const ratioApiSize = (ratio) => { const [w, h] = IMG_RATIOS[ratio] || [1, 1]; return w > h ? "1536x1024" : w < h ? "1024x1536" : "1024x1024"; };
function b64ToImage(b64) {
  return new Promise((res, rej) => { const img = new Image(); img.onload = () => res(img); img.onerror = rej; img.src = `data:image/png;base64,${b64}`; });
}
async function cropImageToRatio(img, ratio) {
  const [rw, rh] = IMG_RATIOS[ratio] || [1, 1];
  const target = rw / rh;
  let sw = img.naturalWidth, sh = img.naturalHeight;
  if (sw / sh > target) sw = Math.round(sh * target); else sh = Math.round(sw / target);
  const sx = Math.round((img.naturalWidth - sw) / 2), sy = Math.round((img.naturalHeight - sh) / 2);
  const c = document.createElement("canvas"); c.width = sw; c.height = sh;
  c.getContext("2d").drawImage(img, sx, sy, sw, sh, 0, 0, sw, sh);
  const blob = await new Promise(r => c.toBlob(r, "image/jpeg", 0.92));
  return new File([blob], `ai-${ratio.replace(":", "x")}-${Date.now()}.jpg`, { type: "image/jpeg" });
}
async function genImageToMedia(prompt, token, userId, ratio = "1:1") {
  const res = await fetch(`${SUPA_URL}/functions/v1/image-gen`, {
    method: "POST",
    headers: { "Content-Type": "application/json", apikey: SUPA_KEY, Authorization: `Bearer ${token}` },
    body: JSON.stringify({ prompt, size: ratioApiSize(ratio) }),
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok || data.error || !data.b64) throw new Error(data.error || "Image generation failed");
  const img = await b64ToImage(data.b64);
  const file = await cropImageToRatio(img, ratio);
  return uploadMedia(file, token, userId);
}

// ── Persistent auth session — survives refresh, auto-renews via the refresh token,
//    and is SHARED between the creator app and public school pages (one key). ──
const SESS_KEY = "senseito_sess";
const readSessLS = () => { try { return JSON.parse(localStorage.getItem(SESS_KEY) || "null"); } catch { return null; } };
const writeSessLS = (s) => { try { s ? localStorage.setItem(SESS_KEY, JSON.stringify(s)) : localStorage.removeItem(SESS_KEY); } catch { } };
// If the URL carries a fresh OAuth hash (#access_token=…), persist it (incl. the refresh token) and clean the URL.
function captureHashSession() {
  try {
    const h = new URLSearchParams((window.location.hash || "").replace(/^#/, ""));
    const at = h.get("access_token");
    if (!at) return null;
    const s = { access_token: at, refresh_token: h.get("refresh_token") || "", expires_at: Date.now() + (parseInt(h.get("expires_in") || "3600", 10) * 1000) };
    writeSessLS(s);
    try { window.history.replaceState(null, "", window.location.pathname + window.location.search); } catch { }
    return s;
  } catch { return null; }
}
async function refreshSessLS(s) {
  if (!s?.refresh_token) { writeSessLS(null); return null; }
  try {
    const r = await fetch(`${SUPA_URL}/auth/v1/token?grant_type=refresh_token`, { method: "POST", headers: { "Content-Type": "application/json", apikey: SUPA_KEY }, body: JSON.stringify({ refresh_token: s.refresh_token }) });
    const j = await r.json().catch(() => ({}));
    if (!r.ok || !j.access_token) { writeSessLS(null); return null; }
    const ns = { access_token: j.access_token, refresh_token: j.refresh_token || s.refresh_token, expires_at: Date.now() + (j.expires_in || 3600) * 1000 };
    writeSessLS(ns); return ns;
  } catch { return null; } // network blip — keep the stored session, retry later
}
// → { token, user } | null. Fresh OAuth hash wins; else the stored session, refreshed when stale.
async function restoreSession() {
  let s = captureHashSession() || readSessLS();
  if (!s) return null;
  if (Date.now() > (s.expires_at || 0) - 120000) s = await refreshSessLS(s);
  if (!s) return null;
  try { const user = await supaFetch("/auth/v1/user", { token: s.access_token }); return { token: s.access_token, user }; }
  catch {
    const ns = await refreshSessLS(s); if (!ns) return null;
    try { const user = await supaFetch("/auth/v1/user", { token: ns.access_token }); return { token: ns.access_token, user }; } catch { return null; }
  }
}

