  return (<div style={{ textAlign: data.align || "center", padding: "4px 0" }}>{/^https?:\/\//i.test(url) ? <a href={url} target="_blank" rel="noopener noreferrer" style={{ textDecoration: "none" }}>{inner}</a> : inner}</div>);
